 namespace WPAICG\Chat\Frontend\Shortcode\FeatureManagerMethods; if (!defined('ABSPATH')) { exit; } function get_ui_flags_logic(array $core_flags, bool $is_pro_plan): array { $ui_flags = []; $ui_flags['starters_ui_enabled'] = ($core_flags['enable_starters_setting'] ?? false); $ui_flags['sidebar_ui_enabled'] = ($core_flags['enable_sidebar_setting'] ?? false) && !($core_flags['popup_enabled'] ?? false); $ui_flags['pdf_ui_enabled'] = ($core_flags['enable_download'] ?? false) && $is_pro_plan; $ui_flags['tts_ui_enabled'] = ($core_flags['enable_tts_setting'] ?? false); return $ui_flags; } 